import{_ as a,p as s,q as n,a1 as e}from"./framework-5866ffd3.js";const t={},c=e(`<h1 id="clock" tabindex="-1"><a class="header-anchor" href="#clock" aria-hidden="true">#</a> clock</h1><p>用于调整 RTC 时间</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>clock命令</strong>用于调整 RTC 时间。 RTC 是电脑内建的硬件时间，执行这项指令可以显示现在时刻，调整硬件时钟的时间，将系统时间设成与硬件时钟之时间一致，或是把系统时间回存到硬件时钟。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>clock <span class="token punctuation">[</span>--adjust<span class="token punctuation">]</span><span class="token punctuation">[</span>--debug<span class="token punctuation">]</span><span class="token punctuation">[</span>--directisa<span class="token punctuation">]</span><span class="token punctuation">[</span>--getepoch<span class="token punctuation">]</span><span class="token punctuation">[</span>--hctosys<span class="token punctuation">]</span><span class="token punctuation">[</span>--set <span class="token parameter variable">--date</span><span class="token operator">=</span><span class="token string">&quot;&lt;日期时间&gt;&quot;</span><span class="token punctuation">]</span>
<span class="token punctuation">[</span>--setepoch <span class="token parameter variable">--epoch</span><span class="token operator">=</span><span class="token operator">&lt;</span> <span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--show<span class="token punctuation">]</span><span class="token punctuation">[</span>--systohc<span class="token punctuation">]</span><span class="token punctuation">[</span>--test<span class="token punctuation">]</span><span class="token punctuation">[</span>--utc<span class="token punctuation">]</span><span class="token punctuation">[</span>--version<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token parameter variable">--adjust</span> 　第一次使用<span class="token string">&quot;--set&quot;</span>或<span class="token string">&quot;--systohc&quot;</span>参数设置硬件时钟，会在/etc目录下产生一个名称为adjtime的文件。当再次使用这两个参数调整硬件时钟，此文件便会记录两次调整间之差异，日后执行clock指令加上<span class="token string">&quot;--adjust&quot;</span>参数时，程序会自动根 据记录文件的数值差异，计算出平均值，自动调整硬件时钟的时间。
<span class="token parameter variable">--debug</span> 　详细显示指令执行过程，便于排错或了解程序执行的情形。
<span class="token parameter variable">--directisa</span> 　告诉clock指令不要通过/dev/rtc设备文件，直接对硬件时钟进行存取。这个参数适用于仅有ISA总线结构的老式电脑。
<span class="token parameter variable">--getepoch</span> 　把系统核心内的硬件时钟新时代数值，呈现到标准输出设备。
<span class="token parameter variable">--hctosys</span> 　Hardware Clock to System Time，把系统时间设成和硬件时钟一致。由于这个动作将会造成系统全面更新文件的存取时间，所以最好在系统启动时就执行它。
--set--date 　设置硬件时钟的日期和时间。
--setepoch--epoch<span class="token operator">=</span><span class="token operator">&lt;</span>年份<span class="token operator">&gt;</span> 　设置系统核心之硬件时钟的新时代数值，年份以四位树字表示。
<span class="token parameter variable">--show</span> 　读取硬件时钟的时间，并将其呈现至标准输出设备。
<span class="token parameter variable">--systohc</span> 　System Time to Hardware Clock，将系统时间存回硬件时钟内。
<span class="token parameter variable">--test</span> 　仅作测试，并不真的将时间写入硬件时钟或系统时间。
<span class="token parameter variable">--utc</span> 　把硬件时钟上的时间时为CUT，有时也称为UTC或UCT。
<span class="token parameter variable">--version</span> 　显示版本信息。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>获取当前的时间</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>clock <span class="token comment"># 获取当前的时间</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>显示UTC时间</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>clock <span class="token parameter variable">-utc</span> <span class="token comment">#显示UTC时间</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,13),p=[c];function o(i,l){return s(),n("div",null,p)}const d=a(t,[["render",o],["__file","clock.html.vue"]]);export{d as default};
